const groqResponse = $input.item.json;
const candidate = $('Validate Required Fields').item.json;

let scoring;
try {
  const rawContent = groqResponse.choices[0].message.content;
  scoring = JSON.parse(rawContent);
} catch (e) {
  return {
    json: {
      name: candidate.name ?? '(unknown)',
      email: candidate.email ?? '',
      location: candidate.location ?? '',
      years_experience: candidate.years_experience ?? '',
      overall_score: 'ERROR',
      technical_skills: 'ERROR',
      experience_relevance: 'ERROR',
      communication_indicators: 'ERROR',
      match_explanation: `Parse error: ${e.message}`,
      flag: 'ERROR',
      scored_at: new Date().toISOString(),
    }
  };
}

const required = ['technical_skills', 'experience_relevance', 'communication_indicators'];
const missing = required.filter(k => scoring[k] == null);
if (missing.length > 0) {
  return {
    json: {
      name: candidate.name ?? '(unknown)',
      email: candidate.email ?? '',
      location: candidate.location ?? '',
      years_experience: candidate.years_experience ?? '',
      overall_score: 'ERROR',
      technical_skills: 'ERROR',
      experience_relevance: 'ERROR',
      communication_indicators: 'ERROR',
      match_explanation: `Incomplete LLM response — missing: ${missing.join(', ')}`,
      flag: 'ERROR',
      scored_at: new Date().toISOString(),
    }
  };
}

const overall = Math.round((
  Number(scoring.technical_skills)         * 0.35 +
  Number(scoring.experience_relevance)      * 0.40 +
  Number(scoring.communication_indicators)  * 0.25
) * 10) / 10;

const flag = overall >= 70 ? 'Qualified'
           : overall >= 45 ? 'Needs Review'
           : 'Unqualified';

return {
  json: {
    name: candidate.name,
    email: candidate.email,
    location: candidate.location,
    years_experience: candidate.years_experience,
    overall_score: overall,
    technical_skills: scoring.technical_skills,
    experience_relevance: scoring.experience_relevance,
    communication_indicators: scoring.communication_indicators,
    match_explanation: scoring.match_explanation ?? '',
    flag,
    scored_at: new Date().toISOString(),
  }
};
